Bash(cd "C:\\Users\\kapla\\astro-atesh" && node -e "
const sharp = require\('sharp'\);
const path = require\('path'\);
const input = path.join\('C:', 'Users', 'kapla', 'Downloads', 'logo_transparent.png'\);
const output = path.join\('C:', 'Users', 'kapla', 'astro-atesh', 'public', 'images', 'logo.png'\);

sharp\(input\)
  .raw\(\)
  .toBuffer\({ resolveWithObject: true }\)
  .then\(\({ data, info }\) => {
    const { width, height, channels } = info;
    const buf = Buffer.from\(data\);

    // Replace near-black pixels with transparent
    for \(let i = 0; i < buf.length; i += channels\) {
      const r = buf[i], g = buf[i+1], b = buf[i+2];
      // If pixel is dark \(black background\) make transparent
      if \(r < 30 && g < 30 && b < 30\) {
        buf[i+3] = 0; // alpha = 0 \(transparent\)
      }
    }

    return sharp\(buf, { raw: { width, height, channels } }\)
      .png\(\)
      .toFile\(output\);
  }\)
  .then\(\(\) => console.log\('Done! Logo saved with transparent background.'\)\)
  .catch\(e => console.error\(e\)\);
")
